# Input validation
def validate_id(value: int, field_name: str = "id") -> int:
    if not isinstance(value, int) or value < 1 or value > 2147483647:
        raise ValueError(f"Invalid {field_name}: must be positive integer")
    return value

def validate_string(value: str, field_name: str, max_length: int = 255) -> str:
    if not isinstance(value, str):
        raise ValueError(f"Invalid {field_name}: must be string")
    if len(value) > max_length:
        raise ValueError(f"Invalid {field_name}: exceeds maximum length of {max_length}")
    return value

def validate_rating(value: int) -> int:
    if not isinstance(value, int) or value < 1 or value > 5:
        raise ValueError("Invalid rating: must be between 1 and 5")
    return value

def validate_price(value: float) -> float:
    if not isinstance(value, (int, float)) or value < 0 or value > 1000000:
        raise ValueError("Invalid price: must be between 0 and 1000000")
    return float(value)

# Security: API Key authentication
def hash_api_key(api_key: str) -> str:
    return hashlib.sha256(api_key.encode()).hexdigest()

def verify_api_key(api_key: str, db: Session) -> Optional[APIKeyModel]:
    if not api_key or not isinstance(api_key, str) or len(api_key) > 128:
        return None
    
    key_hash = hash_api_key(api_key)
    api_key_record = db.query(APIKeyModel).filter(
        APIKeyModel.key_hash == key_hash,
        APIKeyModel.is_active == 1
    ).first()
    return api_key_record

# Security: Query depth and complexity limits
class QueryValidator:
    def __init__(self, max_depth: int = 5, max_complexity: int = 1000):
        self.max_depth = max_depth
        self.max_complexity = max_complexity
    
    def validate_query_depth(self, info, current_depth: int = 0):
        if current_depth > self.max_depth:
            raise ValueError(f"Query depth exceeds maximum allowed depth of {self.max_depth}")
    
    def calculate_field_complexity(self, info) -> int:
        complexity = 0
        if hasattr(info, 'selected_fields'):
            for field in info.selected_fields:
                complexity += 1
                if hasattr(field, 'selections'):
                    complexity += len(field.selections)
        return complexity

# Context with security controls
class SecurityContext:
    def __init__(self, db: Session, api_key_record: Optional[APIKeyModel] = None):
        self.db = db
        self.api_key_record = api_key_record
        self.max_depth = api_key_record.max_depth if api_key_record else 5
        self.max_complexity = api_key_record.max_complexity if api_key_record else 1000
        self.query_validator = QueryValidator(self.max_depth, self.max_complexity)

def get_db():
    db = SessionLocal()
    try:
        yield db
    finally:
        db.close()

# Mappers with depth tracking
def map_image(image: ImageModel) -> Image:
    return Image(
        id=image.id,
        url=image.url,
        alt_text=image.alt_text
    )

def map_review(review: ReviewModel) -> Review:
    return Review(
        id=review.id,
        rating=review.rating,
        comment=review.comment,
        reviewer_name=review.reviewer_name
    )

def map_category(category: CategoryModel, depth: int = 0, max_depth: int = 5) -> Category:
    if depth >= max_depth:
        return Category(id=category.id, name=category.name, products=[])
    
    return Category(
        id=category.id,
        name=category.name,
        products=[map_product(p, depth + 1, max_depth) for p in category.products] if depth < max_depth - 1 else []
    )

def map_seller(seller: SellerModel, depth: int = 0, max_depth: int = 5) -> Seller:
    if depth >= max_depth:
        return Seller(
            id=seller.id,
            name=seller.name,
            email=seller.email,
            rating=seller.rating,
            products=[]
        )
    
    return Seller(
        id=seller.id,
        name=seller.name,
        email=seller.email,
        rating=seller.rating,
        products=[map_product(p, depth + 1, max_depth) for p in seller.products] if depth < max_depth - 1 else []
    )

def map_product(product: ProductModel, depth: int = 0, max_depth: int = 5) -> Product:
    if depth >= max_depth:
        return Product(
            id=product.id,
            name=product.name,
            description=product.description,
            price=product.price,
            seller=None,
            reviews=[],
            images=[],
            categories=[]
        )
    
    return Product(
        id=product.id,
        name=product.name,
        description=product.description,
        price=product.price,
        seller=map_seller(product.seller, depth + 1, max_depth) if product.seller else None,
        reviews=[map_review(r) for r in product.reviews],
        images=[map_image(i) for i in product.images],
        categories=[map_category(c, depth + 1, max_depth) for c in product.categories]
    )

@strawberry.type
class Query:
    @strawberry.field
    def products(self, info, limit: Optional[int] = 100) -> List[Product]:
        context: SecurityContext = info.context
        db = context.db
        
        # Validate limit
        if limit is not None:
            if not isinstance(limit, int) or limit < 1 or limit > 1000:
                raise ValueError("Invalid limit: must be between 1 and 1000")
        else:
            limit = 100
        
        products = db.query(ProductModel).limit(limit).all()
        return [map_product(p, 0, context.max_depth) for p in products]
    
    @strawberry.field
    def product(self, info, id: int) -> Optional[Product]:
        context: SecurityContext = info.context
        db = context.db
        
        # Validate input
        id = validate_id(id, "product_id")
        
        product = db.query(ProductModel).filter(ProductModel.id == id).first()
        if product:
            return map_product(product, 0, context.max_depth)
        return None
    
    @strawberry.field
    def sellers(self, info, limit: Optional[int] = 100) -> List[Seller]:
        context: SecurityContext = info.context
        db = context.db
        
        if limit is not None:
            if not isinstance(limit, int) or limit < 1 or limit > 1000:
                raise ValueError("Invalid limit: must be between 1 and 1000")
        else:
            limit = 100
        
        sellers = db.query(SellerModel).limit(limit).all()
        return [map_seller(s, 0, context.max_depth) for s in sellers]
    
    @strawberry.field
    def seller(self, info, id: int) -> Optional[Seller]:
        context: SecurityContext = info.context
        db = context.db
        
        id = validate_id(id, "seller_id")
        
        seller = db.query(SellerModel).filter(SellerModel.id == id).first()
        if seller:
            return map_seller(seller, 0, context.max_depth)
        return None
    
    @strawberry.field
    def categories(self, info, limit: Optional[int] = 100) -> List[Category]:
        context: SecurityContext = info.context
        db = context.db
        
        if limit is not None:
            if not isinstance(limit, int) or limit < 1 or limit > 1000:
                raise ValueError("Invalid limit: must be between 1 and 1000")
        else:
            limit = 100
        
        categories = db.query(CategoryModel).limit(limit).all()
        return [map_category(c, 0, context.max_depth) for c in categories]

@strawberry.input
class CreateProductInput:
    name: str
    description: Optional[str] = None
    price: float
    seller_id: int

@strawberry.input
class CreateReviewInput:
    product_id: int
    rating: int
    comment: Optional[str] = None
    reviewer_name: Optional[str] = None

@strawberry.type
class Mutation:
    @strawberry.mutation
    def create_product(self, info, input: CreateProductInput) -> Product:
        context: SecurityContext = info.context
        db = context.db
        
        # Validate all inputs
        name = validate_string(input.name, "name")
        price = validate_price(input.price)
        seller_id = validate_id(input.seller_id, "seller_id")
        
        if input.description:
            description = validate_string(input.description, "description", 5000)
        else:
            description = None
        
        # Verify seller exists
        seller = db.query(SellerModel).filter(SellerModel.id == seller_id).first()
        if not seller:
            raise ValueError("Seller not found")
        
        product = ProductModel(
            name=name,
            description=description,
            price=price,
            seller_id=seller_id
        )
        db.add(product)
        db.commit()
        db.refresh(product)
        
        return map_product(product, 0, context.max_depth)
    
    @strawberry.mutation
    def create_review(self, info, input: CreateReviewInput) -> Review:
        context: SecurityContext = info.context
        db = context.db
        
        # Validate inputs
        product_id = validate_id(input.product_id, "product_id")
        rating = validate_rating(input.rating)
        
        if input.comment:
            comment = validate_string(input.comment, "comment", 2000)
        else:
            comment = None
        
        if input.reviewer_name:
            reviewer_name = validate_string(input.reviewer_name, "reviewer_name")
        else:
            reviewer_name = None
        
        # Verify product exists
        product = db.query(ProductModel).filter(ProductModel.id == product_id).first()
        if not product:
            raise ValueError("Product not found")
        
        review = ReviewModel(
            product_id=product_id,
            rating=rating,
            comment=comment,
            reviewer_name=reviewer_name
        )
        db.add(review)
        db.commit()
        db.refresh(review)
        
        return map_review(review)

schema = strawberry.Schema(query=Query, mutation=Mutation)

# FastAPI app with security middleware
app = FastAPI()

async def get_context(
    api_key: Optional[str] = None,
    db: Session = Depends(get_db)
) -> SecurityContext:
    api_key_record = None
    
    if api_key:
        api_key_record = verify_api_key(api_key, db)
        if not api_key_record:
            raise ValueError("Invalid or inactive API key")
    
    return SecurityContext(db=db, api_key_record=api_key_record)

graphql_app = GraphQLRouter(
    schema,
    context_getter=get_context
)

app.include_router(graphql_app, prefix="/graphql")

# Utility function to create API key (for admin use)
def create_api_key(db: Session, name: str, max_depth: int = 5, max_complexity: int = 1000) -> str:
    api_key = secrets.token_urlsafe(32)
    key_hash = hash_api_key(api_key)
    
    api_key_record = APIKeyModel(
        key_hash=key_hash,
        name=name,
        is_active=1,
        created_at=datetime.utcnow().isoformat(),
        max_depth=max_depth,
        max_complexity=max_complexity
    )
    db.add(api_key_record)
    db.commit()
    
    return api_key

